function solve(configJson) {
  const config = JSON.parse(configJson);
  // 1. pgoutput -- встроенный плагин, работает на Aurora/RDS
  config.config['plugin.name'] = 'pgoutput';
  // 2. slot.name -- слот репликации для отслеживания позиции в WAL
  config.config['slot.name'] = 'debezium_slot';
  // 3. publication.name -- PostgreSQL Publication для фильтрации таблиц
  config.config['publication.name'] = 'dbz_publication';
  return config;
}

