questions.solutionCode:
function solve(requirementsJson) {
  const reqs = JSON.parse(requirementsJson);
  return {
    name: reqs.topicPrefix + '-connector',
    config: {
      'connector.class': 'io.debezium.connector.postgresql.PostgresConnector',
      'database.hostname': reqs.hostname,
      'database.port': String(reqs.port),
      'database.user': reqs.user,
      'database.password': reqs.password,
      'database.dbname': reqs.dbname,
      'topic.prefix': reqs.topicPrefix,
      'table.include.list': reqs.tables.join(','),
      'plugin.name': 'pgoutput',
      'slot.name': reqs.slotName,
      'publication.name': reqs.publicationName,
      'snapshot.mode': 'initial'
    }
  };
}
